            bad: { user: "I got everyone to sign a card for you. We all want you to know we're here!", ai: "*(overwhelmed)* I... didn't want everyone to know. This is... a lot.", note: "\u274c Group gesture when they wanted privacy. Intentions were good, execution was exposing." },
            good: { user: "*(leaves coffee on their desk with a note: 'No need to respond. Just wanted you to have this.')*", ai: "*(finds it, tears up, texts later)* That coffee meant everything today. Thank you.", note: "\u2713 Small, private, no pressure to respond. Perfect." },
