            bad: { user: "So what do you do? Where are you from?", ai: "*(polite auto-pilot)* I'm in marketing. From Ohio originally. You?", note: "\u274c Small talk script. Both of you are bored. Neither will remember this." },
            good: { user: "Okay, random question \u2014 what's something you've been thinking about a lot lately? Doesn't have to be deep. Just whatever's on your mind.", ai: "*(surprised, then engaged)* Oh wow, nobody asks that. Actually... I've been obsessed with this idea about...", note: "\u2713 Skipped the script. They lit up. THIS is where introverts thrive." },
